1	export type Cell = [number, number];
2	
3	const neighborOffsets: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	function cellKey(x: number, y: number): string {
10	  return `${x},${y}`;
11	}
12	
13	function parseKey(key: string): Cell {
14	  const [x, y] = key.split(",").map(Number);
15	  return [x, y];
16	}
17	
18	export function nextGeneration(livingCells: Cell[]): Cell[] {
19	  const alive = new Set(livingCells.map(([x, y]) => cellKey(x, y)));
20	
21	  const neighborCounts = new Map<string, number>();
22	  for (const [x, y] of livingCells) {
23	    for (const [dx, dy] of neighborOffsets) {
24	      const key = cellKey(x + dx, y + dy);
25	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
26	    }
27	  }
28	
29	  const result: Cell[] = [];
30	  for (const [key, count] of neighborCounts) {
31	    if (count === 3 || (count === 2 && alive.has(key))) {
32	      result.push(parseKey(key));
33	    }
34	  }
35	
36	  return result;
37	}
38

1	import { describe, it, expect } from "vitest";
