4	describe("Game of Life", () => {
5	  it("should return no living cells for an empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell (underpopulation, 0 neighbors)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells (underpopulation, 1 neighbor each)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive with exactly 2 neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	  it("should keep a live cell alive with exactly 3 neighbors (survival)", () => {
22	    // 2x2 block: each cell has exactly 3 live neighbors
23	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
24	    const result = nextGeneration(block);
25	    expect(result).toContainEqual([0, 0]);
26	  });
27	  it("should kill a live cell with 4 neighbors (overpopulation)", () => {
28	    // Plus pattern: center cell (1,1) has 4 live neighbors
29	    const plus: Cell[] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
30	    const result = nextGeneration(plus);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should bring a dead cell to life with exactly 3 live neighbors (reproduction)", () => {
34	    // L-shape: dead cell (1,1) has exactly 3 live neighbors
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
36	    expect(result).toContainEqual([1, 1]);
37	  });
38	  it("should keep a block pattern unchanged (still life)", () => {
